-- Iscas: colunas extras + seed das 29 (rodar no SQL Editor)
alter table public.blog_templum_iscas add column if not exists slug text;
alter table public.blog_templum_iscas add column if not exists image_url text;
alter table public.blog_templum_iscas add column if not exists segment text;
create unique index if not exists blog_templum_iscas_slug_idx on public.blog_templum_iscas (slug);

on conflict (slug) do update set title=excluded.title, type=excluded.type, description=excluded.description, file_url=excluded.file_url, segment=excluded.segment;
